    || CASE WHEN p_title IS NOT NULL THEN '<header>' || p_title || '</header>' ELSE '' END
    || p_body
    || CASE WHEN p_footer IS NOT NULL THEN '<footer>' || p_footer || '</footer>' ELSE '' END
    || '</article>';
$function$;

CREATE OR REPLACE FUNCTION pgv.esc(p_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT replace(replace(replace(replace(replace(
    coalesce(p_text, ''),
    '&', '&amp;'), '<', '&lt;'), '>', '&gt;'), '"', '&quot;'), '''', '&#39;');
$function$;

CREATE OR REPLACE FUNCTION pgv.accordion(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_count int := array_length(p_items, 1) / 2;
  v_html text := '';
BEGIN
  FOR i IN 0..v_count-1 LOOP
    v_html := v_html || '<details class="pgv-accordion">'
      || '<summary>' || pgv.esc(p_items[i*2+1]) || '</summary>'
      || '<div>' || p_items[i*2+2] || '</div>'
      || '</details>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.accordion(text[]) IS 'Collapsible sections via native details/summary (VARIADIC title/content pairs)';

