CREATE OR REPLACE FUNCTION pgv.radio(p_name text, p_label text, p_options jsonb, p_selected text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_html text;
  v_opt text;
BEGIN
  v_html := '<fieldset><legend>' || pgv.esc(p_label) || '</legend>';
  FOR v_opt IN SELECT jsonb_array_elements_text(p_options)
  LOOP
    v_html := v_html || '<label><input type="radio" name="' || p_name || '" value="' || pgv.esc(v_opt) || '"'
      || CASE WHEN v_opt = p_selected THEN ' checked' ELSE '' END
      || '> ' || pgv.esc(v_opt) || '</label>';
  END LOOP;
  RETURN v_html || '</fieldset>';
END;
$function$;
COMMENT ON FUNCTION pgv.radio(text,text,jsonb,text) IS 'Radio button group (PicoCSS native styling)';

CREATE OR REPLACE FUNCTION pgv.route(p_schema text, p_path text, p_method text DEFAULT 'GET'::text, p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_nav jsonb;
  v_opts jsonb;
  v_brand text;
  v_title text;
  v_fname text;
  v_body text;
  v_detail text;
  v_hint text;
  v_route text;
  v_nargs int;
  v_argtype text;
  v_argname text;
BEGIN
  -- Get nav items
  BEGIN
    EXECUTE format('SELECT %I.nav_items()', p_schema) INTO v_nav;
  EXCEPTION WHEN undefined_function THEN
    RAISE EXCEPTION 'Module % has no nav_items() function', p_schema;
  END;

  -- Get brand (optional, fallback to schema name)
  BEGIN
    EXECUTE format('SELECT %I.brand()', p_schema) INTO v_brand;
  EXCEPTION WHEN undefined_function THEN
    v_brand := initcap(p_schema);
  END;

  -- Get nav options (optional, fallback to empty)
  BEGIN
    EXECUTE format('SELECT %I.nav_options()', p_schema) INTO v_opts;
  EXCEPTION WHEN undefined_function THEN
    v_opts := '{}'::jsonb;
  END;

  -- Derive function name: method + path
  IF p_path = '/' THEN
    v_fname := lower(p_method) || '_index';
  ELSE
    v_fname := lower(p_method) || '_' || replace(replace(trim(BOTH '/' FROM p_path), '/', '_'), '-', '_');
  END IF;

  -- Full route path
  v_route := '/' || p_schema || p_path;

  -- Set route prefix early (pgv.call_ref() needs it)
  PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);

  -- Prefix nav hrefs with schema
  v_nav := (
    SELECT jsonb_agg(
      CASE WHEN (item->>'href') ~ '^https?://'
        THEN item
        ELSE jsonb_set(item, '{href}', to_jsonb('/' || p_schema || (item->>'href')))
      END
    )
    FROM jsonb_array_elements(v_nav) AS item
  );

  -- Introspect function signature (max 1 arg)
  SELECT p.pronargs,
         CASE WHEN p.pronargs > 0 THEN (p.proargtypes::oid[])[0]::regtype::text END,
         CASE WHEN p.pronargs > 0 THEN p.proargnames[1] END
  INTO v_nargs, v_argtype, v_argname
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = p_schema AND p.proname = v_fname AND p.prokind = 'f'
    AND p.pronargs <= 1;

  IF NOT FOUND THEN
    -- GET: return 200 with error page (shell renders HTML, no need for HTTP error)
    -- POST: return 404 so shell shows toast via _err()
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '404', true);
      RETURN '<template data-toast="error">Page non trouvee: ' || pgv.esc(p_method || ' ' || p_path) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, '404', v_route, v_nav,
      pgv.error('404', 'Page non trouvee', 'Le chemin ' || p_method || ' ' || p_path || ' n''existe pas.'), v_opts);
  END IF;

  -- Execute based on signature
  IF v_nargs = 0 THEN
    EXECUTE format('SELECT %I.%I()', p_schema, v_fname) INTO v_body;
  ELSIF v_argtype = 'jsonb' THEN
    EXECUTE format('SELECT %I.%I($1)', p_schema, v_fname) USING p_params INTO v_body;
  ELSIF v_argtype IN ('integer', 'bigint', 'text', 'uuid') THEN
    EXECUTE format('SELECT %I.%I($1::%s)', p_schema, v_fname, v_argtype)
      USING p_params->>v_argname INTO v_body;
  ELSE
    -- Composite type: deserialize jsonb into typed record
    EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%s, $1))', p_schema, v_fname, v_argtype)
      USING p_params INTO v_body;
  END IF;

  -- POST: return raw (toast/redirect templates, no layout)
  IF lower(p_method) = 'post' THEN
    RETURN v_body;
  END IF;

  -- GET: find title from nav
  SELECT item->>'label' INTO v_title
  FROM jsonb_array_elements(v_nav) AS item
  WHERE item->>'href' = v_route;

  IF v_title IS NULL THEN
    v_title := initcap(replace(regexp_replace(v_fname, '^(get|post)_', ''), '_', ' '));
  END IF;

  -- Wrap in page layout
  RETURN pgv.page(v_brand, v_title, v_route, v_nav, v_body, v_opts);

EXCEPTION
  WHEN raise_exception THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT, v_hint = PG_EXCEPTION_HINT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Erreur', v_detail, v_hint), v_opts);
  WHEN invalid_text_representation THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Parametre invalide', v_detail), v_opts);
  WHEN OTHERS THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '500', true);
      RETURN '<template data-toast="error">Erreur interne</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('500', 'Erreur interne', 'Une erreur inattendue est survenue.'), v_opts);
END;
$function$;
COMMENT ON FUNCTION pgv.route(text,text,text,jsonb) IS 'Router: maps method+path to get_*/post_* functions via pg_proc introspection. Supports 0-arg, scalar, jsonb, and composite type parameters.';

CREATE OR REPLACE FUNCTION pgv.diagnose(p_schema text, p_path text DEFAULT '/'::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text;
  v_start timestamptz;
  v_ms numeric;
  v_rows text := '';
  v_err int := 0;
  v_warn int := 0;
  v_ok int := 0;
  v_rec record;
  v_ns text;
  v_fn text;
  v_href text;
  v_params text[];
  v_inputs text[];
  v_missing text[];
  v_pages text[];
  v_page text;
  v_reports text := '';
  v_css_ok boolean;
BEGIN
  -- If path is '*', diagnose all nav pages
  IF p_path = '*' THEN
    BEGIN
      EXECUTE format(
        'SELECT array_agg(item->>''href'') FROM jsonb_array_elements(%I.nav_items()) AS item WHERE NOT (item->>''href'') ~ ''^https?://''',
        p_schema
      ) INTO v_pages;
    EXCEPTION WHEN OTHERS THEN
      -- nav_items() may return TABLE(label, href, icon) instead of jsonb
      EXECUTE format(
        'SELECT array_agg(href) FROM %I.nav_items() WHERE NOT href ~ ''^https?://''',
        p_schema
      ) INTO v_pages;
    END;
  ELSE
    v_pages := ARRAY[p_path];
  END IF;

  FOREACH v_page IN ARRAY v_pages LOOP
    v_rows := '';
    v_err := 0; v_warn := 0; v_ok := 0;

    -- Render page
    v_start := clock_timestamp();
    BEGIN
      v_html := pgv.route(p_schema, v_page, 'GET', '{}'::jsonb);
    EXCEPTION WHEN OTHERS THEN
      v_reports := v_reports || pgv.error('500', p_schema || ':' || v_page, SQLERRM) || chr(10);
      CONTINUE;
    END;
    v_ms := round(extract(epoch from clock_timestamp() - v_start) * 1000, 1);

    -- 1. Inline styles
    IF v_html ~ ' style\s*=\s*"' THEN
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Style | inline `style` detecte |' || chr(10);
      v_err := v_err + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Style | aucun inline style |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- 2. HTMX
    IF v_html ~ '\bhx-' THEN
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | HTMX | attributs hx-* detectes |' || chr(10);
      v_err := v_err + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | HTMX | aucun |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- 3. Raw <table> without <md>
    IF v_html ~ '<table[\s>]' AND v_html !~ '<md' THEN
      v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Table | `<table>` sans `<md>` |' || chr(10);
      v_warn := v_warn + 1;
    END IF;

    -- 4. data-rpc targets
    FOR v_rec IN
      SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, 'data-rpc="([^"]+)"', 'g') t(x)
    LOOP
      IF v_rec.rpc LIKE '%.%' THEN
        v_ns := split_part(v_rec.rpc, '.', 1);
        v_fn := split_part(v_rec.rpc, '.', 2);
      ELSE
        v_ns := p_schema;
        v_fn := v_rec.rpc;
      END IF;

      IF EXISTS (
        SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = v_ns AND p.proname = v_fn
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | RPC | `' || v_ns || '.' || v_fn || '()` |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | RPC | `' || v_ns || '.' || v_fn || '()` introuvable |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 5. Internal href targets
    FOR v_rec IN
      SELECT DISTINCT x[1] AS raw_href FROM regexp_matches(v_html, 'href="(/[^"]*)"', 'g') t(x)
    LOOP
      v_href := v_rec.raw_href;
      IF v_href LIKE '/' || p_schema || '/%' THEN
        v_href := substr(v_href, length(p_schema) + 2);
      ELSIF v_href = '/' || p_schema OR v_href = '/' || p_schema || '/' THEN
        v_href := '/';
      END IF;
      IF v_href LIKE '%?%' THEN v_href := split_part(v_href, '?', 1); END IF;

      v_fn := CASE WHEN v_href = '/' THEN 'get_index'
              ELSE 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_') END;

      IF EXISTS (
        SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = p_schema AND p.proname = v_fn
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_fn || '()` |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_fn || '()` introuvable |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 6. <md> blocks valid
    FOR v_rec IN
      SELECT x[1] AS md_body FROM regexp_matches(v_html, '<md[^>]*>(.*?)</md>', 'g') t(x)
    LOOP
      IF v_rec.md_body ~ '^\s*\|.+\|\s*\n\s*\|[-| ]+\|' THEN
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Markdown | bloc `<md>` valide |' || chr(10);
        v_ok := v_ok + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Markdown | `<md>` sans header valide |' || chr(10);
        v_err := v_err + 1;
      END IF;
    END LOOP;

    -- 7. Form fields vs function signature
    FOR v_rec IN
      SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, '<form[^>]*data-rpc="([^"]+)"', 'g') t(x)
    LOOP
      SELECT proargnames INTO v_params
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema AND p.proname = v_rec.rpc
      LIMIT 1;

      IF v_params IS NOT NULL THEN
        v_inputs := ARRAY(
          SELECT DISTINCT x[1] FROM regexp_matches(v_html, 'name="([^"]+)"', 'g') t(x)
        );
        v_missing := ARRAY(
          SELECT unnest(v_params) EXCEPT SELECT unnest(v_inputs)
        );
        IF array_length(v_missing, 1) > 0 THEN
          v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Form | `' || v_rec.rpc || '()` params sans champ: ' || array_to_string(v_missing, ', ') || ' |' || chr(10);
          v_warn := v_warn + 1;
        ELSE
          v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Form | `' || v_rec.rpc || '()` signature couverte |' || chr(10);
          v_ok := v_ok + 1;
        END IF;
      END IF;
    END LOOP;

    -- 8. CSS class validation
    v_css_ok := true;
    FOR v_rec IN
      SELECT DISTINCT cls FROM (
        SELECT unnest(string_to_array(x[1], ' ')) AS cls
        FROM regexp_matches(v_html, 'class="([^"]*pgv-[^"]*)"', 'g') t(x)
      ) sub WHERE cls LIKE 'pgv-%'
    LOOP
      IF v_rec.cls NOT IN (
        'pgv-lazy','pgv-brand','pgv-burger-li','pgv-burger','pgv-nav-burger',
        'pgv-menu','pgv-menu-open',
        'pgv-badge','pgv-badge-success','pgv-badge-danger','pgv-badge-warning','pgv-badge-info','pgv-badge-primary',
        'pgv-stat','pgv-stat-value','pgv-dl','pgv-error',
        'pgv-alert','pgv-alert-success','pgv-alert-danger','pgv-alert-warning','pgv-alert-info',
        'pgv-empty','pgv-progress','pgv-avatar',
        'pgv-tabs','pgv-tabs-nav','pgv-accordion','pgv-breadcrumb',
        'pgv-tree','pgv-tree-icon','pgv-theme-toggle',
        'pgv-table','pgv-pager','pgv-pager-info','pgv-pager-btns','pgv-pager-dots',
        'pgv-sortable','pgv-canvas','pgv-canvas-vp','pgv-canvas-bar','pgv-canvas-btn','pgv-canvas-zoom','pgv-canvas-sep',
        'pgv-search-results','pgv-search-item','pgv-search-icon','pgv-search-body','pgv-search-more'
      ) THEN
        v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | CSS | classe `' || pgv.esc(v_rec.cls) || '` inconnue |' || chr(10);
        v_warn := v_warn + 1;
        v_css_ok := false;
      END IF;
    END LOOP;
    IF v_css_ok THEN
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | CSS | toutes les classes pgv-* connues |' || chr(10);
      v_ok := v_ok + 1;
    END IF;

    -- Page report
    v_reports := v_reports || pgv.dl(
      'Page', p_schema || ' : ' || v_page,
      'Rendu', v_ms || ' ms',
      'Bilan',
        CASE WHEN v_err > 0 THEN pgv.badge(v_err || ' erreur(s)', 'danger') || ' ' ELSE '' END
        || CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' warning(s)', 'warning') || ' ' ELSE '' END
        || pgv.badge(v_ok || ' ok', 'success'))
      || '<md>' || chr(10)
      || '| Niveau | Check | Detail |' || chr(10)
      || '|--------|-------|--------|' || chr(10)
      || v_rows
      || '</md>' || chr(10);

  END LOOP;

  RETURN v_reports;
END;
$function$;
COMMENT ON FUNCTION pgv.diagnose(text,text) IS 'Diagnose a pgView page: render + check contract (styles, HTMX, RPCs, links, md, forms). Use * for all pages.';

CREATE OR REPLACE FUNCTION pgv.script(p_js text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<script>' || p_js || '</script>';
$function$;

CREATE OR REPLACE FUNCTION pgv.search_item(p_result pgv.search_result)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<li class="pgv-search-item" data-href="' || pgv.esc(p_result.href) || '">'
    || CASE WHEN p_result.icon IS NOT NULL THEN '<span class="pgv-search-icon">' || p_result.icon || '</span> ' ELSE '' END
    || '<span class="pgv-search-body">'
    || '<strong>' || pgv.esc(p_result.label) || '</strong>'
    || CASE WHEN p_result.kind IS NOT NULL THEN ' ' || pgv.badge(p_result.kind) ELSE '' END
    || CASE WHEN p_result.detail IS NOT NULL THEN '<small>' || pgv.esc(p_result.detail) || '</small>' ELSE '' END
    || '</span>'
    || '</li>';
$function$;
COMMENT ON FUNCTION pgv.search_item(pgv.search_result) IS 'Render a single search result as an HTML list item with data-href for shell navigation.';

CREATE OR REPLACE FUNCTION pgv.search(p_query text, p_schema text, p_limit integer DEFAULT 12, p_offset integer DEFAULT 0)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_results pgv.search_result[];
  v_r pgv.search_result;
  v_html text := '';
  v_count int := 0;
  v_total int := 0;
BEGIN
  -- Check module has a search provider
  IF NOT EXISTS (
    SELECT 1 FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema AND p.proname = 'search'
  ) THEN
    RETURN '<div class="pgv-empty"><h4>Recherche non disponible</h4><p>Le module ' || pgv.esc(p_schema) || ' n''a pas de fonction search().</p></div>';
  END IF;

  -- Call module search provider
  EXECUTE format(
    'SELECT array_agg(r ORDER BY r.score DESC) FROM %I.search($1, $2, $3) r',
    p_schema
  ) USING p_query, p_limit + 1, p_offset
  INTO v_results;

  IF v_results IS NULL OR array_length(v_results, 1) = 0 THEN
    RETURN '<div class="pgv-empty"><h4>Aucun resultat</h4><p>Aucune entite ne correspond a "' || pgv.esc(p_query) || '".</p></div>';
  END IF;

  v_total := array_length(v_results, 1);

  -- Render results (limit to p_limit, use +1 to detect hasMore)
  v_html := '<ul class="pgv-search-results">';
  FOREACH v_r IN ARRAY v_results LOOP
    v_count := v_count + 1;
    IF v_count > p_limit THEN EXIT; END IF;
    v_html := v_html || pgv.search_item(v_r);
  END LOOP;
  v_html := v_html || '</ul>';

  -- Has more indicator
  IF v_total > p_limit THEN
    v_html := v_html || '<div class="pgv-search-more" data-offset="' || (p_offset + p_limit) || '">...</div>';
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.search(text,text,integer,integer) IS 'Search dispatcher: calls {schema}.search() convention, renders results as HTML. Returns empty state if no results.';

CREATE OR REPLACE FUNCTION pgv.sel(p_name text, p_label text, p_options jsonb, p_selected text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text; v_opt jsonb; v_val text; v_lbl text;
BEGIN
  v_html := '<label>' || p_label || '<select name="' || p_name || '">';
  v_html := v_html || '<option value="">--</option>';
  FOR v_opt IN SELECT * FROM jsonb_array_elements(p_options) LOOP
    IF jsonb_typeof(v_opt) = 'string' THEN
      v_val := v_opt #>> '{}'; v_lbl := v_val;
    ELSE
      v_val := v_opt->>'value'; v_lbl := coalesce(v_opt->>'label', v_val);
    END IF;
    v_html := v_html || '<option value="' || pgv.esc(v_val) || '"'
      || CASE WHEN v_val = p_selected THEN ' selected' ELSE '' END
      || '>' || pgv.esc(v_lbl) || '</option>';
  END LOOP;
  RETURN v_html || '</select></label>';
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.stat(p_label text, p_value text, p_detail text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<article class="pgv-stat">'
    || '<small>' || pgv.esc(p_label) || '</small>'
    || '<p class="pgv-stat-value">' || p_value || '</p>'
    || CASE WHEN p_detail IS NOT NULL THEN '<small>' || pgv.esc(p_detail) || '</small>' ELSE '' END
    || '</article>';
$function$;

CREATE OR REPLACE FUNCTION pgv.svg_canvas(p_svg text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_id text := 'sc_' || substr(md5(random()::text), 1, 8);
  v_height text := coalesce(p_options->>'height', '60vh');
  v_toolbar boolean := coalesce((p_options->>'toolbar')::boolean, true);
  v_html text;
  v_js text;
BEGIN
  IF p_svg IS NULL OR p_svg = '' THEN RETURN ''; END IF;

  v_html := '<div class="pgv-canvas" id="' || v_id || '">'
    || '<div class="pgv-canvas-vp" id="' || v_id || '_vp" data-height="' || pgv.esc(v_height) || '">'
    || p_svg
    || '</div>';

  IF v_toolbar THEN
    v_html := v_html
      || '<div class="pgv-canvas-bar">'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_out" title="Zoom out">&minus;</button>'
      || '<span class="pgv-canvas-zoom" id="' || v_id || '_zl">100%</span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_in" title="Zoom in">+</button>'
      || '<span class="pgv-canvas-sep"></span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_fit" title="Ajuster">Fit</button>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_reset" title="1:1">1:1</button>'
      || '</div>';
  END IF;

  v_html := v_html || '</div>';

  v_js := $JS$
(function(){
  var id="__ID__",
      vp=document.getElementById(id+"_vp"),
      svg=vp&&vp.querySelector("svg"),
      zl=document.getElementById(id+"_zl");
  if(!vp||!svg||typeof panzoom==="undefined")return;
  if(vp.dataset.height)vp.style.height=vp.dataset.height;
  var pz=panzoom(svg,{maxZoom:20,minZoom:0.05,smoothScroll:false,bounds:true,boundsPadding:0.2});
  function upd(){if(zl)zl.textContent=Math.round(pz.getTransform().scale*100)+"%";}
  pz.on("zoom",upd);
  pz.on("transform",upd);
  var zi=document.getElementById(id+"_in"),
      zo=document.getElementById(id+"_out"),
      fb=document.getElementById(id+"_fit"),
      rb=document.getElementById(id+"_reset");
  if(zi)zi.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,1.3);};
  if(zo)zo.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,0.7);};
  if(rb)rb.onclick=function(){pz.moveTo(0,0);pz.zoomAbs(0,0,1);upd();};
  if(fb)fb.onclick=function(){
    var bb=svg.getBBox(),vw=vp.clientWidth,vh=vp.clientHeight,
        sc=Math.min(vw/(bb.width+bb.x*2),vh/(bb.height+bb.y*2))*0.9,
        ox=(vw-bb.width*sc)/2-bb.x*sc,
        oy=(vh-bb.height*sc)/2-bb.y*sc;
    pz.zoomAbs(0,0,sc);pz.moveTo(ox,oy);upd();
  };
  if(fb){if(vp.clientWidth>0)fb.onclick();else{var io=new IntersectionObserver(function(es){if(es[0].isIntersecting&&vp.clientWidth>0){fb.onclick();io.disconnect();}});io.observe(vp);}}
})();
$JS$;

  v_js := replace(v_js, '__ID__', v_id);
  v_html := v_html || pgv.script(v_js);

  RETURN v_html;
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.tabs(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_count int := array_length(p_items, 1) / 2;
  v_nav text := '';
  v_panels text := '';
BEGIN
  FOR i IN 0..v_count-1 LOOP
    v_nav := v_nav || '<button @click="tab=' || i || '" :class="tab===' || i || ' && ''active''">'
      || pgv.esc(p_items[i*2+1]) || '</button>';
    v_panels := v_panels || '<div x-show="tab===' || i || '">' || p_items[i*2+2] || '</div>';
  END LOOP;
  RETURN '<div class="pgv-tabs" x-data="{tab:0}">'
    || '<nav class="pgv-tabs-nav">' || v_nav || '</nav>'
    || v_panels || '</div>';
END;
$function$;
COMMENT ON FUNCTION pgv.tabs(text[]) IS 'Tabbed panels with Alpine.js state (VARIADIC label/content pairs)';

CREATE OR REPLACE FUNCTION pgv.textarea(p_name text, p_label text, p_value text DEFAULT NULL::text, p_rows integer DEFAULT 3)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label>' || p_label
    || '<textarea name="' || p_name || '" rows="' || p_rows || '">'
    || coalesce(pgv.esc(p_value), '')
    || '</textarea></label>';
$function$;

CREATE OR REPLACE FUNCTION pgv.toggle(p_name text, p_label text, p_checked boolean DEFAULT false)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label><input type="checkbox" name="' || p_name || '" role="switch"'
    || CASE WHEN p_checked THEN ' checked' ELSE '' END
    || '> ' || pgv.esc(p_label) || '</label>';
$function$;
COMMENT ON FUNCTION pgv.toggle(text,text,boolean) IS 'Switch on/off toggle (PicoCSS role=switch)';

CREATE OR REPLACE FUNCTION pgv.tree(p_items jsonb, p_open boolean DEFAULT false, p_depth integer DEFAULT 0, p_root_attrs text DEFAULT ''::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text;
  v_item jsonb;
  v_label text;
  v_href text;
  v_open boolean;
  v_icon text;
  v_badge text;
  v_action jsonb;
  v_attrs text;
  v_prefix text;
  v_suffix text;
  v_li_open text;
BEGIN
  IF p_depth = 0 THEN
    v_html := '<ul class="pgv-tree"' || CASE WHEN p_root_attrs <> '' THEN ' ' || p_root_attrs ELSE '' END || '>';
  ELSE
    v_html := '<ul>';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP
    v_label := v_item->>'label';
    v_href := v_item->>'href';
    v_open := coalesce((v_item->>'open')::boolean, p_open);
    v_icon := v_item->>'icon';
    v_badge := v_item->>'badge';
    v_action := v_item->'action';
    v_attrs := coalesce(v_item->>'attrs', '');

    -- Build prefix (icon = raw HTML, caller is responsible for content)
    v_prefix := CASE WHEN v_icon IS NOT NULL THEN '<span class="pgv-tree-icon">' || v_icon || '</span> ' ELSE '' END;
    v_suffix := '';
    IF v_badge IS NOT NULL THEN
      v_suffix := v_suffix || ' ' || pgv.badge(v_badge);
    END IF;
    IF v_action IS NOT NULL THEN
      IF jsonb_typeof(v_action) = 'string' THEN
        -- Raw HTML string (e.g. Alpine button)
        v_suffix := v_suffix || ' ' || (v_action #>> '{}');
      ELSE
        -- Object -> pgv.action()
        v_suffix := v_suffix || ' ' || pgv.action(
          v_action->>'rpc',
          coalesce(v_action->>'label', v_action->>'rpc'),
          CASE WHEN v_action ? 'params' THEN v_action->'params' ELSE NULL END,
          v_action->>'confirm'
        );
      END IF;
    END IF;

    v_li_open := '<li' || CASE WHEN v_attrs <> '' THEN ' ' || v_attrs ELSE '' END || '>';

    IF v_item ? 'children' THEN
      v_html := v_html || v_li_open || '<details'
        || CASE WHEN v_open THEN ' open' ELSE '' END
        || '><summary>' || v_prefix || pgv.esc(v_label) || v_suffix || '</summary>'
        || pgv.tree(v_item->'children', p_open, p_depth + 1)
        || '</details></li>';
    ELSIF v_href IS NOT NULL THEN
      v_html := v_html || v_li_open || v_prefix || '<a href="' || v_href || '">' || pgv.esc(v_label) || '</a>' || v_suffix || '</li>';
    ELSE
      v_html := v_html || v_li_open || v_prefix || pgv.esc(v_label) || v_suffix || '</li>';
    END IF;
  END LOOP;

  v_html := v_html || '</ul>';
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.tree(jsonb,boolean,integer,text) IS 'Recursive treeview from jsonb array. Nodes: {label, href?, children?, open?, icon?, badge?, action?, attrs?}. icon=raw HTML, action=string(raw HTML) or object(pgv.action).';

GRANT USAGE ON SCHEMA pgv TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv TO web_anon;

-- Schema: pgv_qa
CREATE SCHEMA IF NOT EXISTS pgv_qa;

CREATE OR REPLACE FUNCTION pgv_qa.form_echo(p_name text DEFAULT ''::text, p_email text DEFAULT ''::text, p_role text DEFAULT ''::text, p_notes text DEFAULT ''::text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '<template data-toast="success">Recu: ' || pgv.esc(p_name) || ' (' || pgv.esc(p_role) || ') — ' || pgv.esc(p_email) || CASE WHEN p_notes <> '' THEN ' — ' || pgv.esc(p_notes) ELSE '' END || '</template>'
      || '<template data-redirect="/forms"></template>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.form_echo(text,text,text,text) IS 'Demo form handler echoing submitted name';

CREATE OR REPLACE FUNCTION pgv_qa.get_errors()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_prefix text := coalesce(nullif(current_setting('pgv.route_prefix', true), ''), '');
BEGIN
  RETURN
    '<section><h4>Gestion des erreurs du routeur</h4>'
    || '<p>Le routeur attrape les exceptions et rend des pages d''erreur.</p>'
    || '<div class="grid">'
    || pgv.card('404', '<p>Page inexistante</p>', '<a href="' || v_prefix || '/nexiste/pas">Tester 404</a>')
    || pgv.card('Erreur metier', '<p>RAISE EXCEPTION → 500</p>', '<a href="' || pgv.call_ref('get_test_raise') || '">Tester raise</a>')
    || pgv.card('Erreur cast', '<p>UUID invalide → 400</p>', '<a href="' || pgv.call_ref('get_test_bad_uuid') || '">Tester bad uuid</a>')
    || '</div></section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_errors() IS 'Error handling showcase: 404, RAISE exception routing';

CREATE OR REPLACE FUNCTION pgv_qa.get_test_bad_uuid()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  EXECUTE 'SELECT $1::uuid' USING 'not-a-uuid';
  RETURN '';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_test_bad_uuid() IS 'Error test: invalid UUID cast triggers 400';

CREATE OR REPLACE FUNCTION pgv_qa.get_test_raise()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RAISE EXCEPTION 'Ceci est une erreur metier volontaire'
    USING HINT = 'Le routeur attrape les exceptions et rend une page d''erreur.';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_test_raise() IS 'Error test: RAISE EXCEPTION triggers 500';

CREATE OR REPLACE FUNCTION pgv_qa.get_toast()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN
    '<section><h4>Toasts serveur (data-toast)</h4>'
    || '<p>Chaque bouton POST via data-rpc, le serveur retourne un template data-toast.</p>'
    || '<div class="grid">'
    || '<button data-rpc="toast_success">Toast succes</button>'
    || '<button data-rpc="toast_error" class="secondary">Toast erreur</button>'
    || '</div></section>'
    || '<section><h4>Erreur PostgREST (RAISE)</h4>'
    || '<p>Le serveur RAISE une exception. Le shell parse le JSON PostgREST et affiche un toast.</p>'
    || '<button data-rpc="toast_raise" class="contrast">Declencher RAISE</button>'
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_toast() IS 'Toast showcase: success, error, RAISE exception';

CREATE OR REPLACE FUNCTION pgv_qa.get_dialogs()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN
    '<section><h4>Confirmations (data-confirm)</h4>'
    || '<p>Les boutons data-rpc acceptent un attribut data-confirm qui affiche un confirm() natif.</p>'
    || '<div class="grid">'
    || pgv.action('toast_success', 'Action avec confirmation', NULL::jsonb, 'Etes-vous sur de vouloir continuer ?')
    || pgv.action('toast_error', 'Suppression danger', NULL::jsonb, 'Supprimer definitivement ?', 'danger')
    || '</div></section>'
    || '<section><h4>Dialog modale (data-dialog)</h4>'
    || '<p>Le shell possede un dialog reutilisable. Un bouton data-dialog ouvre une modale et charge du contenu depuis data-src.</p>'
    || '<form>'
    || pgv.input('documents_root', 'text', 'Dossier documents', NULL, false)
    || '<button type="button" data-dialog="folder-picker" data-src="/" data-target="documents_root">Parcourir...</button>'
    || '</form></section>'
    || '<section><h4>Toast apres action</h4>'
    || '<p>Les actions serveur retournent un template data-toast. Le shell extrait le message et affiche un toast.</p>'
    || '<div class="grid">'
    || pgv.action('toast_success', 'Toast succes')
    || pgv.action('toast_error', 'Toast erreur', NULL::jsonb, NULL, 'secondary')
    || pgv.action('toast_raise', 'Toast RAISE', NULL::jsonb, NULL, 'contrast')
    || '</div></section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_dialogs() IS 'Dialog showcase: confirmations, modals, folder picker';

CREATE OR REPLACE FUNCTION pgv_qa.get_settings()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE v_root text;
BEGIN
  SELECT value INTO v_root FROM pgv_qa.setting WHERE key = 'documentsRoot';
  RETURN
    '<section><h4>Documents</h4>'
    || '<form data-rpc="save_settings">'
    || pgv.input('p_documentsroot', 'text', 'Repertoire racine', v_root, true)
    || '<button type="button" class="outline"'
    || ' data-dialog="folder-picker"'
    || ' data-src="' || CASE WHEN v_root IS NOT NULL THEN '/api/browse?path=' || pgv.esc(v_root) ELSE '/api/browse' END || '"'
    || ' data-target="p_documentsroot">Parcourir</button>'
    || '<small>Dossier contenant les documents a indexer</small>'
    || '<button type="submit">Enregistrer</button>'
    || '</form></section>'
    || '<section><h4>Systeme</h4>'
    || pgv.dl('Version', '0.1.0', 'PostgreSQL', version())
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_settings() IS 'Settings page with folder picker and system info';

CREATE OR REPLACE FUNCTION pgv_qa.get_diagnostics()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text := '';
  v_rec record;
BEGIN
  FOR v_rec IN
    SELECT e.value->>'href' AS href, e.value->>'label' AS label
    FROM jsonb_array_elements(pgv_qa.nav_items()) e
  LOOP
    v_body := v_body || '<section><h4>' || pgv.esc(v_rec.label) || ' (' || pgv.esc(v_rec.href) || ')</h4>'
      || pgv.lazy('lazy_diagnose', jsonb_build_object('p_path', v_rec.href))
      || '</section>';
  END LOOP;
  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_diagnostics() IS 'Run pgv.diagnose() on all nav pages and display consolidated report';

