CREATE OR REPLACE FUNCTION pgv_qa.save_settings(p_documentsroot text DEFAULT NULL::text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF p_documentsroot IS NOT NULL AND p_documentsroot <> '' THEN
    INSERT INTO pgv_qa.setting (key, value, updated_at)
    VALUES ('documentsRoot', p_documentsroot, now())
    ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  END IF;
  RETURN '<template data-toast="success">Configuration enregistree</template>'
      || '<template data-redirect="/settings"></template>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.save_settings(text) IS 'Save settings form handler';

CREATE OR REPLACE FUNCTION pgv_qa.search(p_query text, p_limit integer DEFAULT 12, p_offset integer DEFAULT 0)
 RETURNS SETOF pgv.search_result
 LANGUAGE sql
 STABLE
AS $function$
  SELECT
    ROW(
      '/items?id=' || id,
      CASE status WHEN 'draft' THEN '📝' WHEN 'classified' THEN '📁' WHEN 'archived' THEN '🗄️' ELSE '📄' END,
      status,
      name,
      'Item #' || id || ' — ' || to_char(created_at, 'DD/MM/YYYY'),
      CASE
        WHEN lower(name) = lower(p_query) THEN 1.0
        WHEN lower(name) LIKE lower(p_query) || '%' THEN 0.8
        ELSE 0.5
      END::real
    )::pgv.search_result
  FROM pgv_qa.item
  WHERE lower(name) LIKE '%' || lower(p_query) || '%'
  ORDER BY
    CASE
      WHEN lower(name) = lower(p_query) THEN 1.0
      WHEN lower(name) LIKE lower(p_query) || '%' THEN 0.8
      ELSE 0.5
    END DESC,
    name
  LIMIT p_limit
  OFFSET p_offset;
$function$;
COMMENT ON FUNCTION pgv_qa.search(text,integer,integer) IS 'Search provider for pgv_qa demo: searches items by name using ILIKE + trigram-style scoring.';

CREATE OR REPLACE FUNCTION pgv_qa.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE v_body text;
BEGIN
  v_body := pgv.grid(
    pgv.stat('Items', (SELECT count(*)::text FROM pgv_qa.item), 'total'),
    pgv.stat('Draft', (SELECT count(*)::text FROM pgv_qa.item WHERE status = 'draft'), 'a traiter'),
    pgv.stat('Classes', (SELECT count(*)::text FROM pgv_qa.item WHERE status = 'classified'), 'termine')
  );
  v_body := v_body || '<md data-page="3">' || chr(10)
    || '| Nom | Statut | Date |' || chr(10)
    || '|-----|--------|------|' || chr(10);
  SELECT v_body || coalesce(string_agg(
    '| ' || pgv.esc(name)
    || ' | ' || pgv.badge(status,
        CASE status WHEN 'draft' THEN 'warning' WHEN 'classified' THEN 'success' WHEN 'archived' THEN 'default' ELSE 'info' END)
    || ' | ' || to_char(created_at, 'DD/MM/YYYY') || ' |',
    chr(10) ORDER BY created_at DESC
  ), '') INTO v_body FROM pgv_qa.item;
  v_body := v_body || chr(10) || '</md>';
  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_index() IS 'Dashboard with stats grid and paginated item table';

CREATE OR REPLACE FUNCTION pgv_qa.get_svg()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_svg text;
BEGIN
  v_svg := '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 400 300">'
    || '<rect x="10" y="10" width="180" height="120" rx="8" fill="#f59e0b" opacity="0.8"/>'
    || '<text x="100" y="75" text-anchor="middle" fill="white" font-size="16" font-weight="bold">Module A</text>'
    || '<rect x="210" y="10" width="180" height="120" rx="8" fill="#3b82f6" opacity="0.8"/>'
    || '<text x="300" y="75" text-anchor="middle" fill="white" font-size="16" font-weight="bold">Module B</text>'
    || '<rect x="110" y="170" width="180" height="120" rx="8" fill="#10b981" opacity="0.8"/>'
    || '<text x="200" y="235" text-anchor="middle" fill="white" font-size="16" font-weight="bold">Module C</text>'
    || '<line x1="100" y1="130" x2="200" y2="170" stroke="#78716c" stroke-width="2" marker-end="url(#arr)"/>'
    || '<line x1="300" y1="130" x2="200" y2="170" stroke="#78716c" stroke-width="2" marker-end="url(#arr)"/>'
    || '<defs><marker id="arr" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto">'
    || '<path d="M0,0 L10,5 L0,10 Z" fill="#78716c"/></marker></defs>'
    || '</svg>';

  RETURN
    '<section><h4>pgv.svg_canvas (defaut)</h4>'
    || '<p>Viewport interactif avec toolbar zoom, pan a la souris, fit automatique.</p>'
    || pgv.svg_canvas(v_svg)
    || '</section>'
    || '<section><h4>Options: hauteur + sans toolbar</h4>'
    || pgv.svg_canvas(v_svg, '{"height": "30vh", "toolbar": false}'::jsonb)
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_svg() IS 'SVG canvas showcase: interactive SVG with panzoom toolbar';

